import { chromium } from '/tmp/planetfall-pw/node_modules/playwright-core/index.mjs';
import { PNG } from '/tmp/planetfall-pw/node_modules/pngjs/lib/png.js';
import { readFileSync } from 'node:fs';

const executablePath = '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome';
const browser = await chromium.launch({ executablePath, headless: true, args: ['--no-sandbox'] });
const errors = [];
const warnings = [];
const notFound = [];

function imageStats(path) {
  const png = PNG.sync.read(readFileSync(path));
  const { width, height, data } = png;
  const samples = [];
  const points = [
    [Math.floor(width / 2), Math.floor(height / 2)],
    [Math.floor(width / 3), Math.floor(height / 2)],
    [Math.floor(width * 2 / 3), Math.floor(height / 2)],
    [Math.floor(width / 2), Math.floor(height / 3)],
    [Math.floor(width / 2), Math.floor(height * 2 / 3)],
  ];
  let total = 0;
  let varied = 0;
  for (const [x, y] of points) {
    const i = (y * width + x) * 4;
    const rgba = [data[i], data[i + 1], data[i + 2], data[i + 3]];
    samples.push({ x, y, rgba });
    total += rgba[0] + rgba[1] + rgba[2];
    if (rgba[0] !== rgba[1] || rgba[1] !== rgba[2]) varied += 1;
  }
  return { width, height, total, varied, samples, ok: total > 30 && varied >= 2 };
}

async function verifyViewport({ width, height, label, play = false }) {
  const page = await browser.newPage({ viewport: { width, height }, deviceScaleFactor: 1 });
  page.on('console', msg => {
    const text = msg.text();
    if (msg.type() === 'error') errors.push(`${label}: ${text}`);
    if (msg.type() === 'warning') warnings.push(`${label}: ${text}`);
  });
  page.on('pageerror', err => errors.push(`${label}: ${err.message}`));
  page.on('response', res => {
    if (res.status() === 404) notFound.push(`${label}: ${res.url()}`);
  });
  await page.goto('http://127.0.0.1:5173/?view=level4', { waitUntil: 'networkidle' });
  await page.waitForTimeout(900);
  const overlay = await page.locator('.vite-error-overlay, [data-nextjs-dialog], #webpack-dev-server-client-overlay').count();
  const bodyTextLength = await page.evaluate(() => document.body.innerText.trim().length);
  const briefingBox = await page.locator('#tr-briefing .mission-banner-box').boundingBox();
  const countdownBox = await page.locator('#tr-countdown').boundingBox();
  const progressBox = await page.locator('#tr-progress').boundingBox();
  const screenshotPath = `/tmp/planetfall-level4-${label}.png`;
  await page.screenshot({ path: screenshotPath, fullPage: true });
  const initialImage = imageStats(screenshotPath);
  let winVisible = false;
  let leaderboardVisible = false;
  let afterImage = null;
  if (play) {
    await page.keyboard.press('Space');
    await page.waitForTimeout(120);
    await page.keyboard.press('Space');
    await page.waitForTimeout(250);
    for (let i = 0; i < 4; i++) {
      await page.keyboard.press('1');
      await page.waitForTimeout(850);
    }
    winVisible = await page.locator('#tr-win:not(.hidden)').count() > 0;
    leaderboardVisible = await page.locator('#tr-hud.has-leaderboard .leaderboard:not(.hidden)').count() > 0;
    const winPath = `/tmp/planetfall-level4-${label}-win.png`;
    await page.screenshot({ path: winPath, fullPage: true });
    afterImage = imageStats(winPath);
  }
  await page.close();
  return { label, overlay, bodyTextLength, briefingBox, countdownBox, progressBox, screenshotPath, initialImage, winVisible, leaderboardVisible, afterImage };
}

const desktop = await verifyViewport({ width: 1440, height: 900, label: 'desktop', play: true });
const mobile = await verifyViewport({ width: 390, height: 844, label: 'mobile', play: false });
await browser.close();
console.log(JSON.stringify({ errors, warnings, notFound, desktop, mobile }, null, 2));
